using System.ComponentModel;
using System.Text;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient.
/// Uses constructor injection — the SDK resolves HttpClient from DI
/// and creates a new instance of this class per tool invocation.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all items from the API. Returns a JSON array of items.")]
    public async Task<string> ListItems(
        [Description("Maximum number of items to return (1-100)")] int limit = 20,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing items with limit {Limit}", limit);

        using var response = await httpClient.GetAsync($"/items?limit={limit}", cancellationToken);
        response.EnsureSuccessStatusCode();

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Get a single item by its unique identifier.")]
    public async Task<string> GetItem(
        [Description("The unique identifier of the item to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Getting item {Id}", id);

        using var response = await httpClient.GetAsync($"/items/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool(Destructive = false, ReadOnly = false),
     Description("Create a new item with the given name and description.")]
    public async Task<string> CreateItem(
        [Description("Name for the new item")] string name,
        [Description("Optional description of the item")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating item {Name}", name);

        var payload = JsonSerializer.Serialize(new { name, description }, JsonOptions);
        using var content = new StringContent(payload, Encoding.UTF8, "application/json");

        using var response = await httpClient.PostAsync("/items", content, cancellationToken);
        response.EnsureSuccessStatusCode();

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Search items by keyword. Returns matching items as JSON.")]
    public async Task<string> SearchItems(
        [Description("Search keyword to filter items")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching items with query {Query}", query);

        using var response = await httpClient.GetAsync(
            $"/items/search?q={Uri.EscapeDataString(query)}", cancellationToken);
        response.EnsureSuccessStatusCode();

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

